reference_solution:
def decode_message(encoded):
    words = encoded.split(' ')
    decoded_words = [word[::-1] for word in words]
    return ' '.join(decoded_words)

unit_tests:
import unittest

class TestDecodeMessage(unittest.TestCase):
    def test_two_words(self):
        self.assertEqual(decode_message("olleH dlroW"), "Hello World")

    def test_three_words(self):
        self.assertEqual(decode_message("nohtyP si nuf"), "Python is fun")

    def test_single_word(self):
        self.assertEqual(decode_message("edoc"), "code")

    def test_hidden_empty_string(self):
        self.assertEqual(decode_message(""), "")

    def test_hidden_single_character(self):
        self.assertEqual(decode_message("a"), "a")

    def test_hidden_palindrome(self):
        self.assertEqual(decode_message("racecar"), "racecar")

    def test_hidden_punctuation(self):
        self.assertEqual(decode_message("!olleH"), "Hello!")

    def test_hidden_numbers(self):
        self.assertEqual(decode_message("321 654 987"), "123 456 789")

    def test_hidden_single_chars(self):
        self.assertEqual(decode_message("a b c"), "a b c")

    def test_hidden_two_char_words(self):
        self.assertEqual(decode_message("ba dc fe"), "ab cd ef")

if __name__ == '__main__':
    unittest.main()
